1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	};
6	
7	export function runScenario(
8	  steps: { items: { type: string }[] }[],
9	): unknown[] {
10	  return steps.map((step) => ({
11	    premium:
12	      PROCESSING_FEE +
13	      step.items.reduce(
14	        (sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type],
15	        0,
16	      ),
17	  }));
18	}
